def diagnose_boot_issue(partition_size, os_list, bios_config):
    ubuntu_partition = None
    windows_partition = None
    boot_disk = bios_config.get('boot_disk')

    for os_entry in os_list:
        disk = os_entry['disk']
        size = os_entry['partition_size']
        if disk.startswith('sda'):
            if 'Ubuntu' in os_entry.get('os_name', ''):
                ubuntu_partition = disk
            elif 'Windows' in os_entry.get('os_name', ''):
                windows_partition = disk

    # Check if Ubuntu partition is on the same disk as BIOS boot target
    if ubuntu_partition and boot_disk and not ubuntu_partition.startswith(boot_disk):
        return "The Ubuntu partition is on a different disk than the BIOS is configured to boot from. The boot loader may not be installed on the correct partition."

    # Check if Ubuntu partition size is too small (e.g., < 5GB) — could affect boot loader detection
    if partition_size < 5:
        return "The Ubuntu partition size is too small (<5GB), which may prevent the boot loader from being properly installed or detected."

    # If no Ubuntu partition found, or no boot loader installed
    if not ubuntu_partition:
        return "No Ubuntu partition found in the OS list. The boot loader is likely missing or misconfigured."

    # If BIOS is trying to boot from a drive that doesn't contain Ubuntu
    if boot_disk and not any(disk.startswith(boot_disk) for os_entry in os_list for disk in [os_entry['disk']]):
        return "The BIOS is configured to boot from a drive that does not contain any OS partitions (including Ubuntu)."

    return "No clear boot issue detected. Check if the boot loader (GRUB) is installed on the Ubuntu partition and if the BIOS boot order is correctly set."

